document.addEventListener("DOMContentLoaded",function(){const depoimentoSlides=document.querySelectorAll(".depoimento-slide");const prevButton=document.querySelector(".depoimento-prev");const nextButton=document.querySelector(".depoimento-next");const dots=document.querySelectorAll(".depoimento-dot");let currentSlide=0;function showSlide(n){if(depoimentoSlides.length===0)return;depoimentoSlides.forEach(slide=>{slide.classList.remove("active");slide.style.opacity="0";slide.style.transform="translateX(100%)";slide.style.zIndex="0"});if(dots.length>0){dots.forEach(dot=>{dot.classList.remove("active")})}currentSlide=(n+depoimentoSlides.length)%depoimentoSlides.length;if(depoimentoSlides[currentSlide]){depoimentoSlides[currentSlide].classList.add("active");depoimentoSlides[currentSlide].style.opacity="1";depoimentoSlides[currentSlide].style.transform="translateX(0)";depoimentoSlides[currentSlide].style.zIndex="1"}if(dots.length>0&&dots[currentSlide]){dots[currentSlide].classList.add("active")}}if(depoimentoSlides.length>0){showSlide(0);let slideInterval=setInterval(()=>{showSlide(currentSlide+1)},5e3);if(prevButton){prevButton.addEventListener("click",()=>{clearInterval(slideInterval);showSlide(currentSlide-1);slideInterval=setInterval(()=>{showSlide(currentSlide+1)},5e3)})}if(nextButton){nextButton.addEventListener("click",()=>{clearInterval(slideInterval);showSlide(currentSlide+1);slideInterval=setInterval(()=>{showSlide(currentSlide+1)},5e3)})}if(dots.length>0){dots.forEach((dot,index)=>{dot.addEventListener("click",()=>{clearInterval(slideInterval);showSlide(index);slideInterval=setInterval(()=>{showSlide(currentSlide+1)},5e3)})})}const sliderContainer=document.querySelector(".depoimentos-slider");if(sliderContainer){sliderContainer.addEventListener("mouseenter",()=>{clearInterval(slideInterval)});sliderContainer.addEventListener("mouseleave",()=>{slideInterval=setInterval(()=>{showSlide(currentSlide+1)},5e3)})}}});